typedef struct Sample
{
    int id;
    char *name;
} Sample;

int SampleDeepCopy(Sample *dst, const Sample *src)
{
    if (!dst || !src)
    {
        return -1;
    }

    dst->id = src->id;
    dst->name = NULL;

    if (src->name)
    {
        size_t len = strlen(src->name);
        dst->name = (char *)malloc(len + 1);
        if (!dst->name)
        {
            return -1;
        }
        memcpy(dst->name, src->name, len + 1);
    }

    return 0;
}

