#include <time.h>

static int TryOpenPort(void);
static void SleepMs(unsigned ms);

int OpenWithRetry(unsigned timeoutMs)
{
    struct timespec start;
    clock_gettime(CLOCK_MONOTONIC, &start);

    for (;;)
    {
        if (TryOpenPort() == 0)
        {
            return 0;
        }

        struct timespec now;
        clock_gettime(CLOCK_MONOTONIC, &now);
        unsigned elapsedMs = (unsigned)((now.tv_sec - start.tv_sec) * 1000u +
                            (now.tv_nsec - start.tv_nsec) / 1000000u);
        if (elapsedMs >= timeoutMs)
        {
            return -1;
        }

        SleepMs(20);
    }
}

