#include <stdint.h>

typedef struct ByteRing
{
    uint8_t data[128];
    volatile unsigned head;
    volatile unsigned tail;
} ByteRing;

static ByteRing gRx;

void UartRxIsr(uint8_t byte)
{
    unsigned next = (gRx.head + 1u) % 128u;
    if (next != gRx.tail)
    {
        gRx.data[gRx.head] = byte;
        gRx.head = next;
    }
}

int ByteRing_Pop(uint8_t *out)
{
    if (gRx.tail == gRx.head)
    {
        return 0;
    }

    *out = gRx.data[gRx.tail];
    gRx.tail = (gRx.tail + 1u) % 128u;
    return 1;
}

