int fd = shm_open("/my_shared_block", O_CREAT | O_RDWR, 0666);
if (fd < 0)
{
    return -1;
}

ftruncate(fd, 4096);
void *memory = mmap(NULL, 4096, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
if (memory == MAP_FAILED)
{
    close(fd);
    return -1;
}

munmap(memory, 4096);
close(fd);
shm_unlink("/my_shared_block");
#endif

