unsigned short Crc16_Update(unsigned short crc, unsigned char byte)
{
    crc ^= (unsigned short)byte << 8;
    for (int i = 0; i < 8; ++i)
    {
        crc = (crc & 0x8000) ? (unsigned short)((crc << 1) ^ 0x1021) : (unsigned short)(crc << 1);
    }
    return crc;
}

