#include <cerrno>
#include <cstring>
#include <fcntl.h>
#include <stdexcept>
#include <string>
#include <unistd.h>

std::string ReadFilePosix(const char *path)
{
    const int fd = ::open(path, O_RDONLY | O_CLOEXEC);
    if (fd < 0)
        throw std::runtime_error(std::string("open failed: ") + std::strerror(errno));

    std::string output;
    char buffer[4096];
    for (;;)
    {
        const ssize_t count = ::read(fd, buffer, sizeof(buffer));
        if (count == 0) break;
        if (count < 0)
        {
            const int saved = errno;
            ::close(fd);
            throw std::runtime_error(std::string("read failed: ") + std::strerror(saved));
        }
        output.append(buffer, static_cast<std::size_t>(count));
    }
    ::close(fd);
    return output;
}

