#ifdef _WIN32
#include <windows.h>

typedef IPlugin *(*CreatePluginFn)();
typedef void (*DestroyPluginFn)(IPlugin *);

HMODULE module = LoadLibraryA("myplugin.dll");
if (!module)
{
    return -1;
}

auto createPlugin = reinterpret_cast<CreatePluginFn>(GetProcAddress(module, "CreatePlugin"));
auto destroyPlugin = reinterpret_cast<DestroyPluginFn>(GetProcAddress(module, "DestroyPlugin"));
if (!createPlugin || !destroyPlugin)
{
    FreeLibrary(module);
    return -1;
}

IPlugin *plugin = createPlugin();
int result = plugin->Run(42);
destroyPlugin(plugin);
FreeLibrary(module);
#endif

