class BleDllLoader
{
public:
    using ScanFn = int (*)(const char *deviceName, int timeoutMs);

    explicit BleDllLoader(QString fileName)
        : library_(std::move(fileName))
    {
    }

    bool load()
    {
        if (!library_.load())
            return false;

        scan_ = reinterpret_cast<ScanFn>(library_.resolve("ScanBle"));
        return scan_ != nullptr;
    }

    QString errorString() const { return library_.errorString(); }
    bool isLoaded() const { return library_.isLoaded() && scan_ != nullptr; }

    int scan(const char *deviceName, int timeoutMs) const
    {
        return scan_ ? scan_(deviceName, timeoutMs) : -1;
    }

private:
    QLibrary library_;
    ScanFn scan_ = nullptr;
};

