class DeviceModel : public QAbstractListModel
{
    Q_OBJECT
public:
    enum Roles { NameRole = Qt::UserRole + 1, StateRole };
    int rowCount(const QModelIndex &parent = {}) const override
    { return parent.isValid() ? 0 : rows_.size(); }
    QVariant data(const QModelIndex &index, int role) const override
    {
        if (!index.isValid()) return {};
        const auto &row = rows_.at(index.row());
        if (role == NameRole) return row.name;
        if (role == StateRole) return row.state;
        return {};
    }
protected:
    QHash<int, QByteArray> roleNames() const override
    { return {{NameRole, "name"}, {StateRole, "state"}}; }
private:
    struct Row { QString name; QString state; };
    QVector<Row> rows_;
};

const int row = rows_.size();
