class DashboardWindow : public QMainWindow
{
    Q_OBJECT
public:
    DashboardWindow()
    {
        auto *central = new QWidget(this);
        auto *root = new QHBoxLayout(central);

        auto *leftPanel = new QVBoxLayout();
        leftPanel->addWidget(new QLabel("Controls", central));
        leftPanel->addWidget(new QPushButton("Start", central));
        leftPanel->addWidget(new QPushButton("Stop", central));

        auto *cameraView = new QLabel("Camera / process view", central);
        cameraView->setMinimumSize(640, 360);
        cameraView->setFrameShape(QFrame::Box);

        root->addLayout(leftPanel, 0);
        root->addWidget(cameraView, 1);
        setCentralWidget(central);
        statusBar()->showMessage("Ready");
    }
};

