WINUSB_INTERFACE_HANDLE usbHandle = NULL;
if (!WinUsb_Initialize(deviceHandle, &usbHandle))
{
    return FALSE;
}

WINUSB_INTERFACE_HANDLE associated = NULL;
if (WinUsb_GetAssociatedInterface(usbHandle, 0, &associated))
{
    /* use alternate interface */
}

HANDLE deviceHandle = CreateFileA(devicePath, GENERIC_READ | GENERIC_WRITE, FILE_SHARE_READ | FILE_SHARE_WRITE, NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL | FILE_FLAG_OVERLAPPED, NULL);
if (deviceHandle == INVALID_HANDLE_VALUE)
{
    return FALSE;
}

WINUSB_INTERFACE_HANDLE usbHandle = NULL;
if (!WinUsb_Initialize(deviceHandle, &usbHandle))
{
    CloseHandle(deviceHandle);
    return FALSE;
}

WINUSB_PIPE_INFORMATION pipeInfo;
if (WinUsb_QueryPipe(usbHandle, 0, pipeIndex, &pipeInfo))
{
    printf("Pipe ID: 0x%02X\n", pipeInfo.PipeId);
}

USB_INTERFACE_DESCRIPTOR ifaceDesc;
if (WinUsb_QueryInterfaceSettings(usbHandle, 0, &ifaceDesc))
{
    for (UCHAR index = 0; index < ifaceDesc.bNumEndpoints; ++index)
    {
        WINUSB_PIPE_INFORMATION pipeInfo;
        if (WinUsb_QueryPipe(usbHandle, 0, index, &pipeInfo))
        {
            printf("Pipe[%u] id=0x%02X type=%u\n", index, pipeInfo.PipeId, pipeInfo.PipeType);
        }
    }
}

WINUSB_SETUP_PACKET setup = {0};
setup.RequestType = 0xC0;
setup.Request = 0x01;
UCHAR buffer[64] = {0};
ULONG transferred = 0;
WinUsb_ControlTransfer(usbHandle, setup, buffer, sizeof(buffer), &transferred, NULL);

UCHAR rx[512];
ULONG received = 0;
if (!WinUsb_ReadPipe(usbHandle, bulkInPipe, rx, sizeof(rx), &received, NULL))
{
    return FALSE;
}

UCHAR tx[] = { 0x55, 0xAA, 0x01, 0x02 };
ULONG sent = 0;
if (!WinUsb_WritePipe(usbHandle, bulkOutPipe, tx, sizeof(tx), &sent, NULL))
{
    return FALSE;
}

WINUSB_SETUP_PACKET setup = {0};
setup.RequestType = 0x40;
setup.Request = 0x10;
setup.Value = 0x0001;
setup.Index = 0;
setup.Length = 0;

ULONG transferred = 0;
if (!WinUsb_ControlTransfer(usbHandle, setup, NULL, 0, &transferred, NULL))
{
    return FALSE;
}

UCHAR reply[64] = {0};
if (!WinUsb_ReadPipe(usbHandle, bulkInPipe, reply, sizeof(reply), &transferred, NULL))
{
    return FALSE;
}

HDEVINFO infoSet = SetupDiGetClassDevs(&guid, NULL, NULL, DIGCF_PRESENT | DIGCF_DEVICEINTERFACE);
if (infoSet == INVALID_HANDLE_VALUE)
{
    return FALSE;
}

SP_DEVICE_INTERFACE_DATA ifData = {0};
ifData.cbSize = sizeof(ifData);
BOOL ok = SetupDiEnumDeviceInterfaces(infoSet, NULL, &guid, index, &ifData);

DWORD required = 0;
SetupDiGetDeviceInterfaceDetail(infoSet, &ifData, NULL, 0, &required, NULL);
std::vector<BYTE> buffer(required);
auto *detail = reinterpret_cast<SP_DEVICE_INTERFACE_DETAIL_DATA *>(buffer.data());
detail->cbSize = sizeof(SP_DEVICE_INTERFACE_DETAIL_DATA);
SetupDiGetDeviceInterfaceDetail(infoSet, &ifData, detail, required, NULL, NULL);

BYTE buffer[512] = {0};
DWORD regType = 0;
if (SetupDiGetDeviceRegistryProperty(infoSet, &devInfo, SPDRP_FRIENDLYNAME, &regType, buffer, sizeof(buffer), NULL))
{
    printf("%s\n", (char *)buffer);
}

SP_DEVICE_INTERFACE_DATA ifData = {0};
ifData.cbSize = sizeof(ifData);
SetupDiOpenDeviceInterface(infoSet, devicePath, 0, &ifData);

HDEVINFO infoSet = SetupDiGetClassDevs(&interfaceGuid, NULL, NULL, DIGCF_PRESENT | DIGCF_DEVICEINTERFACE);
if (infoSet == INVALID_HANDLE_VALUE)
{
    return FALSE;
}

for (DWORD index = 0;; ++index)
{
    SP_DEVICE_INTERFACE_DATA ifData = {0};
    ifData.cbSize = sizeof(ifData);
    if (!SetupDiEnumDeviceInterfaces(infoSet, NULL, &interfaceGuid, index, &ifData))
    {
        break;
    }

    DWORD required = 0;
    SetupDiGetDeviceInterfaceDetail(infoSet, &ifData, NULL, 0, &required, NULL);
    std::vector<BYTE> buffer(required);
    auto *detail = reinterpret_cast<SP_DEVICE_INTERFACE_DETAIL_DATA *>(buffer.data());
    detail->cbSize = sizeof(SP_DEVICE_INTERFACE_DETAIL_DATA);
    if (SetupDiGetDeviceInterfaceDetail(infoSet, &ifData, detail, required, NULL, NULL))
    {
        printf("%s\n", detail->DevicePath);
    }
}

SetupDiDestroyDeviceInfoList(infoSet);

USHORT count = 0;
BluetoothGATTGetServices(deviceHandle, 0, NULL, &count, BLUETOOTH_GATT_FLAG_NONE);
std::vector<BTH_LE_GATT_SERVICE> services(count);
BluetoothGATTGetServices(deviceHandle, count, services.data(), &count, BLUETOOTH_GATT_FLAG_NONE);

USHORT serviceCount = 0;
BluetoothGATTGetServices(deviceHandle, 0, NULL, &serviceCount, BLUETOOTH_GATT_FLAG_NONE);
std::vector<BTH_LE_GATT_SERVICE> services(serviceCount);
BluetoothGATTGetServices(deviceHandle, serviceCount, services.data(), &serviceCount, BLUETOOTH_GATT_FLAG_NONE);

if (!services.empty())
{
    USHORT charCount = 0;
    BluetoothGATTGetCharacteristics(deviceHandle, &services[0], 0, NULL, &charCount, BLUETOOTH_GATT_FLAG_NONE);
    std::vector<BTH_LE_GATT_CHARACTERISTIC> chars(charCount);
    BluetoothGATTGetCharacteristics(deviceHandle, &services[0], charCount, chars.data(), &charCount, BLUETOOTH_GATT_FLAG_NONE);
}

