BYTE *buffer = NULL;
DWORD maxLength = 0;
DWORD currentLength = 0;
HRESULT hr = mediaBuffer->Lock(&buffer, &maxLength, &currentLength);

DWORD streamIndex = 0;
DWORD streamFlags = 0;
LONGLONG timestamp = 0;
IMFSample *sample = NULL;
HRESULT hr = reader->ReadSample(MF_SOURCE_READER_FIRST_VIDEO_STREAM, 0, &streamIndex, &streamFlags, &timestamp, &sample);
if (SUCCEEDED(hr) && sample)
{
    IMFMediaBuffer *buffer = NULL;
    hr = sample->ConvertToContiguousBuffer(&buffer);
    if (SUCCEEDED(hr))
    {
        BYTE *bytes = NULL;
        DWORD maxLen = 0;
        DWORD curLen = 0;
        hr = buffer->Lock(&bytes, &maxLen, &curLen);
        if (SUCCEEDED(hr))
        {
            /* process frame bytes */
            buffer->Unlock();
        }
        buffer->Release();
    }
    sample->Release();
}
